class Solution:
    def minSetSize(self, arr):
        from collections import Counter
        counts = sorted(Counter(arr).values(), reverse=True)
        half = len(arr) // 2
        removed = 0
        for i, c in enumerate(counts):
            removed += c
            if removed >= half:
                return i + 1
        return len(counts)

